import math

def is_prime(n):
    if n < 2:
        return False
    if n == 2 or n == 3:
        return True
    if n % 2 == 0 or n % 3 == 0:
        return False
    i = 5
    while i * i <= n:
        if n % i == 0 or n % (i + 2) == 0:
            return False
        i += 6
    return True

def generate_primes():
    num = 2
    while True:
        if is_prime(num):
            yield num
        num += 1

if __name__ == '__main__':
    # Örnek kullanım: İlk 10 asal sayıyı üret
    prime_generator = generate_primes()
    print("İlk 10 asal sayı:")
    for _ in range(10):
        print(next(prime_generator))

    # Başka bir örnek: 100'den küçük tüm asal sayıları listele
    print("\n100'den küçük asal sayılar:")
    primes_less_than_100 = []
    prime_gen_2 = generate_primes()
    while True:
        p = next(prime_gen_2)
        if p >= 100:
            break
        primes_less_than_100.append(p)
    print(primes_less_than_100)
